#!/bin/sh
set -e
# Build script generated by Z98 bootstrap compiler

gcc -std=c89 -m32 -pedantic -Wall -O2 -I. -Isrc/include -c zig_runtime.c -o zig_runtime.o
gcc -std=c89 -m32 -pedantic -Wall -O2 -I. -Isrc/include -c builtin.c -o builtin.o
gcc -std=c89 -m32 -pedantic -Wall -O2 -I. -Isrc/include -c multi_module_token.c -o multi_module_token.o
gcc -std=c89 -m32 -pedantic -Wall -O2 -I. -Isrc/include -c multi_module_main.c -o multi_module_main.o
gcc -m32 -o app zig_runtime.o builtin.o multi_module_token.o multi_module_main.o
